 78	unsigned char I_TBS2I_MCS(unsigned char I_TBS) {
 79	  unsigned char I_MCS = -1;
 80	
 81	  ///note: change from <= to < to go from choosing higher modulation rather than high code-rate
 82	  if (I_TBS <= 9)
 83	    I_MCS = I_TBS;
 84	  else if (I_TBS <= 15)
 85	    I_MCS = I_TBS + 1;
 86	  else if (I_TBS > 15 && I_TBS <= 26)
 87	    I_MCS = I_TBS + 2;
 88	
 89	#ifdef OUTPUT_DEBUG
 90	  printf("I_MCS: %d, from mod_order %d and I_TBS %d\n",I_MCS,modOrder(I_MCS,I_TBS),I_TBS);
 91	
 92	  if (I_MCS == 0xFF) getchar();
 93	
 94	#endif
 95	  return I_MCS;
