 98	uint16_t find_nb_rb_DL(uint8_t mcs, uint32_t bytes, uint16_t nb_rb_max, uint16_t rb_gran) {
 99	  if (bytes == 0 || mcs > 28 || nb_rb_max == 0)
100	    return 0;
101	  const uint32_t bits = bytes << 3;
102	  const unsigned char I_TBS = get_I_TBS(mcs);
103	
104	  uint32_t TBS = TBStable[I_TBS][nb_rb_max - 1];
105	  if (bits >= TBS)     // is nb_rb_max too small?
106	    return nb_rb_max;
107	
108	  TBS = TBStable[I_TBS][rb_gran - 1];
109	  if (bits <= TBS)     // is rb_gran RB enough?
110	    return rb_gran;
111	
112	  nb_rb_max += nb_rb_max % rb_gran; // round up to full RBG
113	  uint16_t hi = nb_rb_max/rb_gran - 1;
114	  uint16_t lo = 0;
115	  uint16_t p = (hi + lo) / 2;
116	  for (; lo + 1 != hi; p = (hi + lo) / 2) {
117	    const uint16_t rbi = (p + 1) * rb_gran - 1;  // convert "RBG" -> RB
118	    TBS = TBStable[I_TBS][rbi];
119	    if (bits <= TBS)  // need less RBs
120	      hi = p;
121	    else              // need more RBs
122	      lo = p;
123	  }
124	  return (hi + 1) * rb_gran;
125	}
126	
127	uint32_t get_TBS_DL(uint8_t mcs, uint16_t nb_rb) {
128	  uint32_t TBS;
129	
130	  if ((nb_rb > 0) && (mcs < 29)) {
131	    TBS = TBStable[get_I_TBS(mcs)][nb_rb-1];
132	    TBS = TBS>>3;
133	    return(TBS);
134	  } else {
135	    return(uint32_t)0;
136	  }
137	}
138	
139	uint32_t get_TBS_UL(uint8_t mcs, uint16_t nb_rb) {
140	  uint32_t TBS = 0;
141	
142	  if ((nb_rb > 0) && (mcs < 29)) {
143	    TBS = TBStable[get_I_TBS_UL(mcs)][nb_rb-1];
144	    TBS = TBS>>3;
145	    return(TBS);
146	  } else {
147	    return(uint32_t)0;
148	  }
149	}
