157	  if ((subframe!=0) && (subframe!=5) && (subframe!=6))  // if not PBCH/SSS or SSS
158	    return(0);
159	
160	  //first half of slot and TDD (no adjustments in first slot except for subframe 6 - PSS)
161	  if ((symbol<(nsymb>>1))&&
162	      (frame_type == TDD)&&
163	      (subframe!=6))
164	    return(0);
165	
166	  // after PBCH
167	  if (frame_type==TDD) { //TDD
168	    if ((symbol>((nsymb>>1)+3)) &&
169	        (symbol!=(nsymb-1)))  ///SSS
170	      return(0);
171	
172	    if ((subframe==5) && (symbol!=(nsymb-1))) ///SSS
173	      return(0);
174	
175	    if ((subframe==6) && (symbol!=2)) /// PSS
176	      return(0);
177	  } else { // FDD
178	    if ((symbol>((nsymb>>1)+3)) ||
179	        (symbol<((nsymb>>1)-2)))
180	      return(0);
181	
182	    if ((subframe==5) && (symbol!=((nsymb>>1)-1))&& (symbol!=((nsymb>>1)-2)))
183	      return(0);
184	
185	    if (subframe==6)
186	      return(0);
187	  }
188	
189	  if ((N_RB_DL&1) == 1) { // ODD N_RB_DL
